import os
from reaction_utils import parse_reaction_file

def write_sample_files():
    # Create only the TSV file; YAML file is missing
    tsv_content = """reaction_id\tequation
r1\tA -> B
r2\tB -> C
"""
    with open('sample_reactions.tsv', 'w') as f:
        f.write(tsv_content)

write_sample_files()

# Parse reaction files; handle missing YAML file gracefully
parsed_tsv = []
parsed_yaml = []
try:
    parsed_tsv = list(parse_reaction_file('sample_reactions.tsv'))
except Exception as e:
    print('Error parsing TSV:', e)
try:
    parsed_yaml = list(parse_reaction_file('sample_reactions.yaml'))
except FileNotFoundError:
    print('Error: YAML file not found')
except Exception as e:
    print('Error parsing YAML:', e)

def main():
    print('Parsed TSV reactions:')
    for rxn in parsed_tsv:
        print(rxn)
    if not parsed_yaml:
        print('No YAML reactions parsed.')

if __name__ == '__main__':
    main()

